(()=>{var s="https://api.example.com/status";chrome.runtime.onInstalled.addListener(()=>{chrome.alarms.create("fetchApiStatus",{periodInMinutes:5}),e()});chrome.alarms.onAlarm.addListener(t=>{t.name==="fetchApiStatus"&&e()});async function e(){try{let t=await fetch(s);if(!t.ok)throw new Error("Network response was not ok");let a=await t.text();chrome.storage.local.set({apiStatus:a})}catch{chrome.storage.local.set({apiStatus:"Error fetching status"})}}})();
